mod common;

use std::time::Duration;

use common::lsp_client::{TestClient, file_uri};

/// Absolute path to the completion test schema.
fn completion_schema_path() -> String {
    format!(
        "{}/tests/fixtures/completion-schema.json",
        env!("CARGO_MANIFEST_DIR")
    )
}

