/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, `type`, and `oneOf`/`anyOf` branches to generate value
/// suggestions. Duplicates across composed branches are collapsed.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_value_suggestions(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Deduplication key for a `ValueSuggestion`, used to prevent duplicate
/// items when merging oneOf / anyOf branches.
fn suggestion_key(s: &ValueSuggestion) -> String {
    match s {
        ValueSuggestion::Enum(v) => format!("E:{}", serde_json::to_string(v).unwrap_or_default()),
        ValueSuggestion::Const(v) => format!("C:{}", serde_json::to_string(v).unwrap_or_default()),
        ValueSuggestion::Boolean => "B:boolean".to_string(),
        ValueSuggestion::Null => "N:null".to_string(),
    }
}

/// Recursively collect value suggestions from a schema, following oneOf / anyOf
/// branches and `$ref`.  `const` and `enum` clauses short-circuit recursion for
/// that sub-tree (they are definitive).  Type-based suggestions (`boolean`,
/// `null`) do *not* short-circuit, so that composed branches can contribute
/// additional values.
fn collect_value_suggestions(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Check for const.
    if let Some(const_val) = schema.get("const") {
        let s = ValueSuggestion::Const(const_val.clone());
        let key = suggestion_key(&s);
        if seen.insert(key) {
            suggestions.push(s);
        }
        return;
    }

    // Check for enum.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            let s = ValueSuggestion::Enum(val.clone());
            let key = suggestion_key(&s);
            if seen.insert(key) {
                suggestions.push(s);
            }
        }
        return;
    }

    // Check for type-based suggestions (single string).
    if let Some(type_str) = schema.get("type").and_then(|v| v.as_str()) {
        match type_str {
            "boolean" => {
                let key = suggestion_key(&ValueSuggestion::Boolean);
                if seen.insert(key) {
                    suggestions.push(ValueSuggestion::Boolean);
                }
            }
            "null" => {
                let key = suggestion_key(&ValueSuggestion::Null);
                if seen.insert(key) {
                    suggestions.push(ValueSuggestion::Null);
                }
            }
            _ => {}
        }
    }

    // Check for type-based suggestions (array – nullable types).
    if let Some(type_arr) = schema.get("type").and_then(|v| v.as_array()) {
        for t in type_arr {
            if let Some(t_str) = t.as_str() {
                match t_str {
                    "boolean" => {
                        let key = suggestion_key(&ValueSuggestion::Boolean);
                        if seen.insert(key) {
                            suggestions.push(ValueSuggestion::Boolean);
                        }
                    }
                    "null" => {
                        let key = suggestion_key(&ValueSuggestion::Null);
                        if seen.insert(key) {
                            suggestions.push(ValueSuggestion::Null);
                        }
                    }
                    _ => {}
                }
            }
        }
    }

    // Recurse into oneOf branches.
    if let Some(one_of) = schema.get("oneOf").and_then(|v| v.as_array()) {
        for branch in one_of {
            collect_value_suggestions(root, branch, suggestions, seen, depth + 1);
        }
    }

    // Recurse into anyOf branches.
    if let Some(any_of) = schema.get("anyOf").and_then(|v| v.as_array()) {
        for branch in any_of {
            collect_value_suggestions(root, branch, suggestions, seen, depth + 1);
        }
    }
}

