/// Build a JSON document with an absolute $schema pointing to the composed schema.
fn composed_doc_with_schema(content: &str) -> String {
    let schema = composed_schema_path();
    if content.is_empty() {
        format!(r#"{{"$schema": "{schema}"}}"#)
    } else {
        format!(r#"{{"$schema": "{schema}", {content}}}"#)
    }
}

/// Find the byte offset of a placeholder marker `◊` in the source text,
/// returning the offset and the text with the marker removed.
fn cursor_at(text: &str) -> (u32, String) {
    let pos = text.find('◊').expect("missing `◊` cursor marker");
    let clean = text.replacen('◊', "", 1);
    (pos as u32, clean)
}

