-/// Build a JSON document with an absolute $schema pointing to the composed schema.
-fn composed_doc_with_schema(content: &str) -> String {
+/// Build a document with the composed schema and a property value position,
+/// returning the cursor column and the full content.
+///
+/// `property` is the key name and `placeholder` is the dummy value that
+/// follows the colon (e.g. `"null"`).  The cursor is placed right after the
+/// `": "` separator.
+fn composed_value_doc(property: &str, placeholder: &str) -> (u32, String) {
     let schema = composed_schema_path();
-    if content.is_empty() {
-        format!(r#"{{"$schema": "{schema}"}}"#)
-    } else {
-        format!(r#"{{"$schema": "{schema}", {content}}}"#)
-    }
+    let content = format!(
+        r#"{{"$schema": "{schema}", "{property}": {placeholder}}}"#
+    );
+    let needle = format!(r#""{property}": "#);
+    let cursor_col = content.find(&needle).unwrap() + needle.len();
+    (cursor_col as u32, content)
 }

-/// Find the byte offset of a placeholder marker `◊` in the source text,
-/// returning the offset and the text with the marker removed.
-fn cursor_at(text: &str) -> (u32, String) {
-    let pos = text.find('◊').expect("missing `◊` cursor marker");
-    let clean = text.replacen('◊', "", 1);
-    (pos as u32, clean)
-}
